const CHECK_ICON = `<svg width="16" height="16" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg" aria-hidden="true"><path d="M5 12.5L10 17.5L19 7" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"/></svg>`;

const CROSS_ICON = `<svg width="14" height="14" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg" aria-hidden="true"><path d="M6 6L18 18M18 6L6 18" stroke="currentColor" stroke-width="2.5" stroke-linecap="round"/></svg>`;

interface CallbackPageContent {
  badgeVariant: "success" | "danger" | "neutral";
  badgeIcon: string;
  title: string;
  body: string;
}

function escapeHtml(text: string): string {
  return text
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;")
    .replace(/'/g, "&#39;");
}

function getCallbackPageContent(
  result: CallbackParseResult
): CallbackPageContent {
  switch (result.status) {
    case "success":
      return {
        badgeVariant: "success",
        badgeIcon: CHECK_ICON,
        title: "You're all set",
        body: "The Phoenix CLI is now connected. You can close this tab and return to your terminal.",
      };
    case "access_denied":
      return {
        badgeVariant: "neutral",
        badgeIcon: CROSS_ICON,
        title: "Authorization cancelled",
        body: "No access was granted. You can close this tab — rerun px auth login if this was a mistake.",
      };
    case "invalid":
      return {
        badgeVariant: "danger",
        badgeIcon: CROSS_ICON,
        title: "Something went wrong",
        body: `${escapeHtml(result.message)} Return to your terminal and try running px auth login again.`,
      };
    default:
      return assertNever(result);
  }
}

function assertNever(value: never): never {
  throw new Error(`Unsupported callback status: ${String(value)}`);
}

/**
 * Render the standalone HTML page shown in the browser after the OAuth2
 * authorization redirect lands on the CLI's loopback callback server. The
 * page is fully self-contained (inline styles and SVG) because the loopback
 * server serves nothing else.
 */
export function renderOAuthCallbackPage(result: CallbackParseResult): string {
  const content = getCallbackPageContent(result);
  return `<!doctype html>
<html lang="en">
<head>
<meta charset="utf-8" />
<meta name="viewport" content="width=device-width, initial-scale=1" />
<meta name="color-scheme" content="light dark" />
<title>Phoenix CLI login</title>
<style>
  * { box-sizing: border-box; margin: 0; padding: 0; }
  html { color-scheme: light dark; }
  html, body { height: 100%; }
  body {
    font-family: system-ui, sans-serif;
    background-color: Canvas;
    color: CanvasText;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    padding: 24px;
  }
  main {
    max-width: 420px;
    display: flex;
    flex-direction: column;
    align-items: center;
    text-align: center;
  }
  .mark { position: relative; margin-bottom: 24px; }
  .badge {
    position: absolute;
    right: -10px;
    bottom: -6px;
    width: 22px;
    height: 22px;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    background-color: Canvas;
    box-shadow: inset 0 0 0 1.5px currentColor;
  }
  .badge--success { color: #3d9a63; }
  .badge--danger { color: #d64545; }
  .badge--neutral { color: GrayText; }
  h1 { font-size: 20px; font-weight: 600; margin-bottom: 10px; }
  p { font-size: 14px; line-height: 1.6; color: GrayText; overflow-wrap: anywhere; }
  p code { font-family: ui-monospace, monospace; font-size: 13px; }
</style>
</head>
<body>
  <main>
    <div class="mark">
      ${PHOENIX_MARK_SVG}
      <div class="badge badge--${content.badgeVariant}">${content.badgeIcon}</div>
    </div>
    <h1>${content.title}</h1>
    <p>${content.body.replace(/px auth login/g, "<code>px auth login</code>")}</p>
  </main>
</body>
</html>`;
}
